const appId = $vars.WEIMI_APP_ID;
const secret = $vars.WEIMI_SECRET_KEY;
const paramsObj = { deviceCodes: "" };
const paramJson = JSON.stringify(paramsObj);
const nonce = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
const timestamp = Date.now().toString();
const rawString = `secretKey=${secret},nonce=${nonce},timestamp=${timestamp},appId=${appId},paramJson=${paramJson}`;
return { appId, nonce, timestamp, paramJson, rawString, url: $('Config1').first().json.BASE_URL + '/ext/device-profile' };

const appId = $vars.WEIMI_APP_ID;
const secret = $vars.WEIMI_SECRET_KEY;
const paramsObj = {"current": 1, "size": 1000};
const paramJson = JSON.stringify(paramsObj);
const nonce = Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
const timestamp = Date.now().toString();
const rawString = `secretKey=${secret},nonce=${nonce},timestamp=${timestamp},appId=${appId},paramJson=${paramJson}`;
return { appId, nonce, timestamp, paramJson, rawString, url: $('Config1').first().json.BASE_URL + '/ext/today-order-page' };

const results = [];

const deviceNode = $('Split Devices1').all();
const deviceNameMap = {};
deviceNode.forEach(item => {
  if (item.json.deviceCode) {
    deviceNameMap[item.json.deviceCode] = item.json.deviceName;
  }
});

let priceMap = {};
try {
  const priceData = $('Get All Prices1').first().json.data || [];
  priceData.forEach(machine => {
    if (machine.aisles) {
      machine.aisles.forEach(product => {
        const key = `${machine.deviceCode}_${product.goodsId}`;
        priceMap[key] = product.price;
      });
    }
  });
} catch (error) {
  console.log('Price fetch skipped or failed: ' + error);
}

const transactions = $input.all();

for (const transaction of transactions) {
  const record = transaction.json;
  const currentDeviceCode = record.deviceCode;
  const deviceName = deviceNameMap[currentDeviceCode] || 'Unknown Machine';

  if (record.detailList && Array.isArray(record.detailList)) {
    let itemCounter = 1;

    for (const product of record.detailList) {
      const totalPaid = product.payAmount ? product.payAmount / 100 : 0;
      const salePrice = product.salePrice
        ? product.salePrice / 100
        : (product.goodsPrice ? product.goodsPrice / 100 : 0);

      const lookupKey = `${currentDeviceCode}_${product.goodsId}`;
      const unitPriceCents = priceMap[lookupKey];

      let unitPrice = 0;
      let calculatedQty = 1;

      if (unitPriceCents && unitPriceCents > 0) {
        unitPrice = unitPriceCents / 100;
        calculatedQty = Math.round(totalPaid / unitPrice) || 1;
      } else if (salePrice > 0) {
        unitPrice = salePrice;
        calculatedQty = 1;
      } else {
        unitPrice = totalPaid;
        calculatedQty = 1;
      }

      // total_amount = unit price × qty (line total, not unit price alone)
      const lineTotalAmount = Math.round(unitPrice * calculatedQty * 100) / 100;

      let adjustedTime = product.shipmentTime;
      if (adjustedTime) {
        let dt = new Date(adjustedTime.replace(' ', 'T'));
        dt.setHours(dt.getHours() - 4);
        let yyyy = dt.getFullYear();
        let mm = String(dt.getMonth() + 1).padStart(2, '0');
        let dd = String(dt.getDate()).padStart(2, '0');
        let hh = String(dt.getHours()).padStart(2, '0');
        let min = String(dt.getMinutes()).padStart(2, '0');
        let sec = String(dt.getSeconds()).padStart(2, '0');
        adjustedTime = `${yyyy}-${mm}-${dd} ${hh}:${min}:${sec}`;
      }

      results.push({
        'Machine ID':               currentDeviceCode,
        'Machine Name':             deviceName,
        'Item Rank':                `item${itemCounter}`,
        'Internal transaction S/N': record.tradeNoIn || record.tradeNo || record.orderId,
        'Product name':             product.goodsName,
        'Unit Price':               unitPrice,
        'Qty':                      calculatedQty,
        'Paid amount':              totalPaid,
        'Total amount':             lineTotalAmount,
        'Delivery status':          product.shipmentStatus === 1 ? 'Successful' : 'Failed',
        'Time':                     adjustedTime,
      });

      itemCounter++;
    }
  }
}

return results;

// ═══════════════════════════════════════════════════════════
// UNIFIED REPORT BUILDER (UPDATED)
// Now includes Total Sales, Paid Amount, and Variance columns
// Adds ALLMCC superset group (any machine name containing 'MCC')
// ═══════════════════════════════════════════════════════════
const items = $input.all();
const today = new Date().toLocaleDateString('en-GB');

// ── Helper: build full HTML report from a set of items ──
function buildReport(rows) {
  const totalSales = rows.reduce((s, r) => s + (r.json['Total amount'] || 0), 0);
  const totalPaid = rows.reduce((s, r) => s + (r.json['Paid amount'] || 0), 0);
  const totalDelta = totalSales - totalPaid;
  const totalQty = rows.reduce((s, r) => s + (r.json['Qty'] || 0), 0);
  const uniqueM = [...new Set(rows.map(r => r.json['Machine Name']))].length;
  const okCount = rows.filter(r => r.json['Delivery status'] === 'Successful').length;

  // Flow A: Summary
  const summary = `Today's sales: ${totalQty} items sold across ${uniqueM} machines, generating AED ${totalPaid.toFixed(2)} in revenue with ${okCount} successful deliveries.`;

  // Flow B: By machine table
  const machAgg = {};
  rows.forEach(r => {
    const mn = r.json['Machine Name'];
    if (!machAgg[mn]) machAgg[mn] = { sales: 0, paid: 0, qty: 0 };
    machAgg[mn].sales += r.json['Total amount'] || 0;
    machAgg[mn].paid += r.json['Paid amount'] || 0;
    machAgg[mn].qty += r.json['Qty'] || 0;
  });
  const sortedMach = Object.entries(machAgg).sort((a,b) => b[1].paid - a[1].paid);
  let flowB = '<h4>Sales Summary by Machine</h4><table border="1" cellpadding="5" cellspacing="0" style="border-collapse:collapse;width:100%">';
  flowB += '<tr style="background:#f2f2f2"><th>Machine Name</th><th>Total Sales (AED)</th><th>Paid Amount (AED)</th><th>Variance (AED)</th><th>Total Quantity</th></tr>';
  sortedMach.forEach(([mn, d]) => {
    const delta = d.sales - d.paid;
    flowB += `<tr><td>${mn}</td><td>AED ${d.sales.toFixed(2)}</td><td>AED ${d.paid.toFixed(2)}</td><td>AED ${delta.toFixed(2)}</td><td>${d.qty}</td></tr>`;
  });
  flowB += '</table><br/>';

  // Flow D: By product table
  const prodAgg = {};
  rows.forEach(r => {
    const pn = r.json['Product name'];
    if (!prodAgg[pn]) prodAgg[pn] = { sales: 0, paid: 0, qty: 0 };
    prodAgg[pn].sales += r.json['Total amount'] || 0;
    prodAgg[pn].paid += r.json['Paid amount'] || 0;
    prodAgg[pn].qty += r.json['Qty'] || 0;
  });
  const sortedProd = Object.entries(prodAgg).sort((a,b) => b[1].paid - a[1].paid);
  let gq = 0, gs = 0, gp = 0;
  let flowD = '<div style="font-family:Arial,sans-serif;color:#333"><h4>Total Sales by Product (All Machines)</h4>';
  flowD += '<table border="1" cellpadding="5" cellspacing="0" style="border-collapse:collapse;width:100%">';
  flowD += '<tr style="background:#f8f9fa;text-align:left"><th>Product Name</th><th>Total Quantity</th><th>Total Sales (AED)</th><th>Paid Amount (AED)</th><th>Variance (AED)</th></tr>';
  sortedProd.forEach(([pn, d]) => {
    const delta = d.sales - d.paid;
    flowD += `<tr><td>${pn}</td><td>${d.qty}</td><td>${d.sales.toFixed(2)} AED</td><td>${d.paid.toFixed(2)} AED</td><td>${delta.toFixed(2)} AED</td></tr>`;
    gq += d.qty; gs += d.sales; gp += d.paid;
  });
  const gd = gs - gp;
  flowD += `<tr style="font-weight:bold;background:#f0f0f0"><td>GRAND TOTAL</td><td>${gq}</td><td>${gs.toFixed(2)} AED</td><td>${gp.toFixed(2)} AED</td><td>${gd.toFixed(2)} AED</td></tr></table></div>`;

  // Flow C: Machine detail
  const machDetail = {};
  rows.forEach(r => {
    const mn = r.json['Machine Name'], pn = r.json['Product name'];
    if (!machDetail[mn]) machDetail[mn] = { prods: {}, ts: 0, tp: 0, tq: 0 };
    if (!machDetail[mn].prods[pn]) machDetail[mn].prods[pn] = { s: 0, p: 0, q: 0 };
    machDetail[mn].prods[pn].s += r.json['Total amount'] || 0;
    machDetail[mn].prods[pn].p += r.json['Paid amount'] || 0;
    machDetail[mn].prods[pn].q += r.json['Qty'] || 0;
    machDetail[mn].ts += r.json['Total amount'] || 0;
    machDetail[mn].tp += r.json['Paid amount'] || 0;
    machDetail[mn].tq += r.json['Qty'] || 0;
  });
  const sortedDetail = Object.entries(machDetail).sort((a,b) => b[1].tp - a[1].tp);
  let flowC = '<h4>Detailed Items Sold by Machine</h4>';
  sortedDetail.forEach(([mn, md]) => {
    flowC += `<h3>${mn}</h3><table border="1" cellpadding="5" cellspacing="0" style="border-collapse:collapse;width:100%;margin-bottom:20px">`;
    flowC += '<tr style="background:#f2f2f2;text-align:left"><th>Product Name</th><th>Quantity</th><th>Sales (AED)</th><th>Paid Amount (AED)</th><th>Variance (AED)</th></tr>';
    Object.entries(md.prods).sort((a,b) => b[1].p - a[1].p).forEach(([pn, pd]) => {
      const delta = pd.s - pd.p;
      flowC += `<tr><td>${pn}</td><td>${pd.q}</td><td>${pd.s.toFixed(2)} AED</td><td>${pd.p.toFixed(2)} AED</td><td>${delta.toFixed(2)} AED</td></tr>`;
    });
    const mdDelta = md.ts - md.tp;
    flowC += `<tr style="font-weight:bold;background:#f0f0f0"><td>TOTAL</td><td>${md.tq}</td><td>${md.ts.toFixed(2)} AED</td><td>${md.tp.toFixed(2)} AED</td><td>${mdDelta.toFixed(2)} AED</td></tr></table>`;
  });

  return `<h3>Daily Sales Report</h3><p>${summary}</p><br/>${flowB}<br/>${flowD}<br/>${flowC}`;
}

// ── Build Telegram message ──
function buildTelegram(rows) {
  if (!rows.length) return '📊 <b>Daily Sales Report</b>\n\nNo sales recorded for today yet.';
  const machines = {};
  let gt = 0, gq = 0;
  rows.forEach(r => {
    const mn = r.json['Machine Name'], pn = r.json['Product name'];
    if (!machines[mn]) machines[mn] = { prods: {}, tp: 0, tq: 0 };
    if (!machines[mn].prods[pn]) machines[mn].prods[pn] = { p: 0, q: 0 };
    machines[mn].prods[pn].p += r.json['Paid amount'] || 0;
    machines[mn].prods[pn].q += r.json['Qty'] || 0;
    machines[mn].tp += r.json['Paid amount'] || 0;
    machines[mn].tq += r.json['Qty'] || 0;
    gt += r.json['Paid amount'] || 0;
    gq += r.json['Qty'] || 0;
  });
  let txt = `📊 <b>Daily Sales Report</b>\n💰 <b>Grand Total:</b> ${gq} items | ${gt.toFixed(2)} AED\n\n`;
  Object.entries(machines).sort((a,b) => b[1].tp - a[1].tp).forEach(([mn, md]) => {
    txt += `🤖 <b>${mn}</b>\n<i>Total: ${md.tq} items | ${md.tp.toFixed(2)} AED</i>\n`;
    Object.entries(md.prods).sort((a,b) => b[1].p - a[1].p).forEach(([pn, pd]) => {
      txt += `▪️ ${pn}: ${pd.q} qty (${pd.p.toFixed(2)} AED)\n`;
    });
    txt += '\n';
  });
  return txt;
}

// ── Split items by machine group ──
const voxmcc = items.filter(i => (i.json['Machine Name'] || '').includes('VOXMCC'));
const voxmm = items.filter(i => (i.json['Machine Name'] || '').includes('VOXM') && !(i.json['Machine Name'] || '').includes('VOXMCC'));
const omd = items.filter(i => (i.json['Machine Name'] || '').includes('OMD'));
const iris = items.filter(i => (i.json['Machine Name'] || '').includes('IRIS'));
// ALLMCC = superset of every machine whose name contains 'MCC' (includes VOXMCC and any other MCC-tagged machine)
const allmcc = items.filter(i => (i.json['Machine Name'] || '').includes('MCC'));

// ── Build all outputs ──
return [{
  json: {
    // Per-group reports (only if group has data)
    voxmcc_html: voxmcc.length ? buildReport(voxmcc) : null,
    voxmcc_subject: voxmcc.length ? `Daily Sales Report - VOXMCC - ${today}` : null,
    voxmm_html: voxmm.length ? buildReport(voxmm) : null,
    voxmm_subject: voxmm.length ? `Daily Sales Report - VOXMM - ${today}` : null,
    omd_html: omd.length ? buildReport(omd) : null,
    omd_subject: omd.length ? `Daily Sales Report - OMD - ${today}` : null,
    iris_html: iris.length ? buildReport(iris) : null,
    iris_subject: iris.length ? `Daily Sales Report - IRIS - ${today}` : null,
    // ALLMCC (superset) report
    allmcc_html: allmcc.length ? buildReport(allmcc) : null,
    allmcc_subject: allmcc.length ? `Daily Sales Report - ALL MCC - ${today}` : null,
    // Combined report
    all_html: buildReport(items),
    all_subject: `Daily Sales Report - ${today}`,
    // Telegram
    telegramText: buildTelegram(items)
  }
}];

const items = $input.all();
if (!items.length) return [{ json: { p_items: [] } }];

const payload = items.map(i => ({
  internal_txn_sn: i.json['Internal transaction S/N'],
  machine_name: i.json['Machine Name'],
  product_name: i.json['Product name'],
  unit_price: String(i.json['Unit Price']),
  qty: String(i.json['Qty']),
  paid_amount: String(i.json['Paid amount']),
  total_amount: String(i.json['Total amount']),
  delivery_status: i.json['Delivery status'],
  time: i.json['Time'],
  item_rank: i.json['Item Rank']
}));

return [{ json: { p_items: payload } }];
